AND (


            () = #{regionCode}
            OR (
                () IS NULL
                AND (
                    () = #{postcode}

                        OR (
                            () < 1000
                            AND () = #{postcodePrefix}
                        )

                )
            )


            () = #{postcode}

                OR (
                    () < 1000
                    AND () = #{postcodePrefix}
                )



)

mapper.select:
SELECT i.bi_seq, i.title, i.content, i.bi_category, i.location_scope, COALESCE(i.read_count, 0) AS read_count, COALESCE(i.like_count, 0) AS like_count, (SELECT COUNT(*) FROM board_comment bc WHERE bc.bi_seq = i.bi_seq AND (bc.delete_yn IS NULL OR bc.delete_yn != 'Y')) AS comment_count, i.fix_yn, i.place_name, i.place_address, i.place_lat, i.place_lng, CASE WHEN COALESCE(i.urgent_resolved_yn, 'N') = 'Y' THEN true ELSE false END AS urgent_resolved, i.urgent_resolved_date, i.reg_id, m.name AS reg_user_name, COALESCE(i.reg_user_region_name, m.region_name) AS reg_user_region_name, m.parenting_stage AS reg_user_parenting_stage, m.is_honor_neighbor AS reg_user_honor_neighbor, i.reg_date, CASE WHEN EXISTS ( SELECT 1 FROM board_item_like bil WHERE bil.bi_seq = i.bi_seq AND bil.mb_id = #{memberId}::uuid ) THEN true ELSE false END AS liked, CASE WHEN EXISTS (SELECT 1 FROM board_file bf WHERE bf.bi_seq = i.bi_seq) THEN true ELSE false END AS has_file FROM board_item i JOIN member m ON i.reg_id = m.id WHERE i.bo_seq = #{boardId} AND i.fix_yn = 'Y' AND (i.delete_yn IS NULL OR i.delete_yn != 'Y')
AND i.bi_category = #{category}
ORDER BY i.reg_date DESC

SELECT i.bi_seq, i.title, i.content, i.bi_category, i.location_scope, COALESCE(i.read_count, 0) AS read_count, COALESCE(i.like_count, 0) AS like_count, (SELECT COUNT(*) FROM board_comment bc WHERE bc.bi_seq = i.bi_seq AND (bc.delete_yn IS NULL OR bc.delete_yn != 'Y')) AS comment_count, i.fix_yn, i.place_name, i.place_address, i.place_lat, i.place_lng, CASE WHEN COALESCE(i.urgent_resolved_yn, 'N') = 'Y' THEN true ELSE false END AS urgent_resolved, i.urgent_resolved_date, i.reg_id, m.name AS reg_user_name, COALESCE(i.reg_user_region_name, m.region_name) AS reg_user_region_name, m.parenting_stage AS reg_user_parenting_stage, m.is_honor_neighbor AS reg_user_honor_neighbor, i.reg_date, CASE WHEN EXISTS ( SELECT 1 FROM board_item_like bil WHERE bil.bi_seq = i.bi_seq AND bil.mb_id = #{memberId}::uuid ) THEN true ELSE false END AS liked, CASE WHEN EXISTS (SELECT 1 FROM board_file bf WHERE bf.bi_seq = i.bi_seq) THEN true ELSE false END AS has_file FROM board_item i JOIN member m ON i.reg_id = m.id WHERE i.bo_seq = #{boardId} AND i.fix_yn IS NULL AND (i.delete_yn IS NULL OR i.delete_yn != 'Y')
AND i.bi_category = #{category}
ORDER BY (COALESCE(i.read_count, 0) + COALESCE(i.like_count, 0)) DESC LIMIT 3

SELECT i.bi_seq, i.title, i.content, i.bi_category, i.location_scope, COALESCE(i.read_count, 0) AS read_count, COALESCE(i.like_count, 0) AS like_count, (SELECT COUNT(*) FROM board_comment bc WHERE bc.bi_seq = i.bi_seq AND (bc.delete_yn IS NULL OR bc.delete_yn != 'Y')) AS comment_count, i.fix_yn, i.place_name, i.place_address, i.place_lat, i.place_lng, CASE WHEN COALESCE(i.urgent_resolved_yn, 'N') = 'Y' THEN true ELSE false END AS urgent_resolved, i.urgent_resolved_date, i.reg_id, m.name AS reg_user_name, COALESCE(i.reg_user_region_name, m.region_name) AS reg_user_region_name, m.parenting_stage AS reg_user_parenting_stage, m.is_honor_neighbor AS reg_user_honor_neighbor, i.reg_date, CASE WHEN EXISTS ( SELECT 1 FROM board_item_like bil WHERE bil.bi_seq = i.bi_seq AND bil.mb_id = #{memberId}::uuid ) THEN true ELSE false END AS liked, CASE WHEN EXISTS (SELECT 1 FROM board_file bf WHERE bf.bi_seq = i.bi_seq) THEN true ELSE false END AS has_file, b.bo_slug AS board_slug, b.bo_title AS board_title FROM board_item i JOIN member m ON i.reg_id = m.id JOIN board b ON i.bo_seq = b.bo_seq WHERE b.bo_use_yn = 'Y' AND b.bo_read_auth = 'USER' AND (i.delete_yn IS NULL OR i.delete_yn != 'Y') /* 동네 게시판: postcode 일치하는 글만, 일반 게시판: 전체 */ AND ( COALESCE(b.bo_neighbor_yn, 'N') != 'Y'
OR () = #{postcode}
)
AND LOWER(i.title) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
AND LOWER(i.content) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
AND LOWER(m.name) LIKE LOWER(CONCAT('%', #{keyword}, '%'))
AND (LOWER(i.title) LIKE LOWER(CONCAT('%', #{keyword}, '%')) OR LOWER(i.content) LIKE LOWER(CONCAT('%', #{keyword}, '%')))
ORDER BY CASE WHEN i.fix_yn = 'Y' THEN 0 ELSE 1 END, i.reg_date DESC LIMIT #{limit} OFFSET #{offset}
